Here's a modern MSTest approach for testing your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenResponseIsNotSuccess()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenIsCanceled()
    {
        var handler = new MockHttpMessageHandler("content", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(5));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // Fail-safe: test fails if it hangs beyond 5s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.IsNotNull(result);
    }

    // Reusable mock handler — avoids mocking framework dependency
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| **Async tests** | Return `async Task` — MSTest awaits them natively |
| **Timeout guard** | `[Timeout(5000)]` fails the test if it hangs |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **HttpClient testing** | Custom `HttpMessageHandler` — no mocking library needed |
| **Exception assertion** | `Assert.ThrowsExceptionAsync<T>` for async throws |

**MSTest v3+ notes:**
- Never use `async void` — always `async Task`.
- `[Timeout]` works cooperatively with async tests (it cancels the test's implicit token).
- In MSTest v4, prefer `Assert.ThrowsExactlyAsync<T>` over `ThrowsExceptionAsync<T>` for exact type matching.
